import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { adminService } from '../../services/api';

const EMPTY = { title:'',companyName:'',description:'',location:'',jobType:'Full-time',salaryPackage:'',eligibleBranches:'',minimumCgpa:'',skills:'',applicationDeadline:'',totalPositions:'',status:'ACTIVE' };
const DEPT_ABBR = {
  'Computer Science & Engineering': 'CSE',
  'Electronics & Communication': 'ECE',
  'Mechanical Engineering': 'ME',
  'Civil Engineering': 'CE',
  'Electrical Engineering': 'EE',
  'Information Technology': 'IT',
  'Master of Computer Applications': 'MCA'
};

export default function AdminJobs() {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editJob, setEditJob] = useState(null);
  const [form, setForm] = useState(EMPTY);
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();
  const set = k => e => setForm(p => ({ ...p, [k]: e.target.value }));

  const fetchJobs = () => {
    setLoading(true);
    adminService.getAllJobs().then(r => setJobs(r.data)).catch(() => {}).finally(() => setLoading(false));
  };
  useEffect(fetchJobs, []);

  const openCreate = () => { setForm(EMPTY); setEditJob(null); setShowModal(true); };
  const openEdit = job => {
    setForm({
      title: job.title || '', companyName: job.companyName || '', description: job.description || '',
      location: job.location || '', jobType: job.jobType || 'Full-time', salaryPackage: job.salaryPackage || '',
      eligibleBranches: job.eligibleBranches || '', minimumCgpa: job.minimumCgpa || '',
      skills: job.skills || '', applicationDeadline: job.applicationDeadline || '',
      totalPositions: job.totalPositions || '', status: job.status || 'ACTIVE',
    });
    setEditJob(job);
    setShowModal(true);
  };

  const handleSave = async e => {
    e.preventDefault(); setSaving(true);
    // Validation
    if (!form.title.trim()) {
      toast.error('Job title is required.');
      setSaving(false);
      return;
    }
    if (!form.companyName.trim()) {
      toast.error('Company name is required.');
      setSaving(false);
      return;
    }
    if (!form.description.trim()) {
      toast.error('Job description is required.');
      setSaving(false);
      return;
    }
    if (!form.location.trim()) {
      toast.error('Location is required.');
      setSaving(false);
      return;
    }
    if (!form.salaryPackage.trim()) {
      toast.error('Salary/package is required.');
      setSaving(false);
      return;
    }
    if (!form.totalPositions) {
      toast.error('Total positions is required.');
      setSaving(false);
      return;
    }
    if (!form.minimumCgpa) {
      toast.error('Minimum CGPA is required.');
      setSaving(false);
      return;
    }
    if (!form.applicationDeadline) {
      toast.error('Application deadline is required.');
      setSaving(false);
      return;
    }
    if (!form.eligibleBranches.trim()) {
      toast.error('Eligible departments is required.');
      setSaving(false);
      return;
    }
    if (!form.skills.trim()) {
      toast.error('Required skills is required.');
      setSaving(false);
      return;
    }
    try {
      const payload = { ...form, minimumCgpa: form.minimumCgpa ? parseFloat(form.minimumCgpa) : null, totalPositions: form.totalPositions ? parseInt(form.totalPositions) : null };
      if (editJob) { await adminService.updateJob(editJob.id, payload); toast.success('Job updated!'); }
      else { await adminService.createJob(payload); toast.success('Job created!'); }
      setShowModal(false); fetchJobs();
    } catch { toast.error('Failed to save job.'); }
    finally { setSaving(false); }
  };

  const handleDelete = async id => {
    if (!window.confirm('Delete this job posting?')) return;
    try { await adminService.deleteJob(id); toast.success('Job deleted.'); fetchJobs(); }
    catch { toast.error('Delete failed.'); }
  };

  const statusBadge = s => {
    if (s === 'ACTIVE') return <span className="badge badge-active">Active</span>;
    if (s === 'CLOSED') return <span className="badge badge-closed">Closed</span>;
    return <span className="badge badge-pending">Draft</span>;
  };

  return (
    <>
      <div className="topbar">
        <div><div className="topbar-title">Manage Jobs</div><div className="topbar-sub">Create and manage job postings for students</div></div>
        <button className="btn btn-primary" onClick={openCreate}>+ Create Job</button>
      </div>
      <div className="page-content">
        {loading && <div className="spinner-wrap"><div className="spinner" /></div>}
        {!loading && jobs.length === 0 && (
          <div className="card" style={{ textAlign: 'center', padding: 40 }}>
            <p style={{ color: 'var(--gray-400)', marginBottom: 16 }}>No jobs posted yet.</p>
            <button className="btn btn-primary" onClick={openCreate}>Create Your First Job</button>
          </div>
        )}

        <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
          {jobs.length > 0 && (
            <div className="table-wrapper">
              <table>
                <thead><tr><th>Job Title</th><th>Company</th><th>Type</th><th>Package</th><th>Deadline</th><th>Applicants</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>
                  {jobs.map(j => (
                    <tr key={j.id}>
                      <td style={{ fontWeight: 500 }}>{j.title}</td>
                      <td>{j.companyName}</td>
                      <td style={{ fontSize: 12 }}>{j.jobType || '—'}</td>
                      <td style={{ fontSize: 12 }}>{j.salaryPackage || '—'}</td>
                      <td style={{ fontSize: 12, color: 'var(--gray-400)' }}>{j.applicationDeadline ? new Date(j.applicationDeadline).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : '—'}</td>
                      <td style={{ fontWeight: 600, color: 'var(--navy)' }}>{j.applicantCount}</td>
                      <td>{statusBadge(j.status)}</td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <button className="btn btn-sm btn-info" onClick={() => navigate(`/admin/jobs/${j.id}/applicants`)}>Applicants</button>
                          <button className="btn btn-sm btn-outline" onClick={() => openEdit(j)}>Edit</button>
                          <button className="btn btn-sm btn-danger" onClick={() => handleDelete(j.id)}>Delete</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <h3 className="modal-title">{editJob ? 'Edit Job' : 'Create New Job'}</h3>
            <form onSubmit={handleSave}>
              <div className="form-row">
                <div className="form-group"><label>Job Title</label><input type="text" required value={form.title} onChange={set('title')} /></div>
                <div className="form-group"><label>Company Name</label><input type="text" required value={form.companyName} onChange={set('companyName')} /></div>
              </div>
              <div className="form-group"><label>Description</label><textarea rows={3} required value={form.description} onChange={set('description')} /></div>
              <div className="form-row">
                <div className="form-group"><label>Location</label><input type="text" required value={form.location} onChange={set('location')} /></div>
                <div className="form-group"><label>Job Type</label>
                  <select required value={form.jobType} onChange={set('jobType')}>
                    <option>Full-time</option><option>Internship</option><option>Contract</option><option>Part-time</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Salary / Package</label><input type="text" required value={form.salaryPackage} onChange={set('salaryPackage')} /></div>
                <div className="form-group"><label>Total Positions</label><input type="number" required value={form.totalPositions} onChange={set('totalPositions')} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Minimum CGPA</label><input type="number" step="0.1" required value={form.minimumCgpa} onChange={set('minimumCgpa')} /></div>
                <div className="form-group"><label>Application Deadline</label><input type="date" required value={form.applicationDeadline} onChange={set('applicationDeadline')} /></div>
              </div>
              <div className="form-group"><label>Eligible Departments (comma separated abbreviations)</label><input type="text" required value={form.eligibleBranches} onChange={set('eligibleBranches')} /></div>
              <div className="form-group"><label>Required Skills (comma separated)</label><input type="text" required value={form.skills} onChange={set('skills')} /></div>
              <div className="form-group"><label>Status</label>
                <select required value={form.status} onChange={set('status')}>
                  <option value="ACTIVE">Active</option><option value="DRAFT">Draft</option><option value="CLOSED">Closed</option>
                </select>
              </div>
              <div className="btn-row">
                <button type="button" className="btn btn-outline" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Saving…' : editJob ? 'Update Job' : 'Create Job'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
}
